const descriptionIndex = new Map<string, string>(Object.entries(DESCRIPTIONS));

/**
 * Look up a human-readable description by ticker symbol.
 * Returns null if no description exists for this ticker.
 *
 * This is presentation content only — independent of catalog membership,
 * governance, or recommendation eligibility.
 */
export function lookupLibraryDescription(symbol: string): string | null {
  return descriptionIndex.get(symbol.toUpperCase()) ?? null;
}

/**
 * Get the number of descriptions in the library.
 */
export function descriptionLibrarySize(): number {
  return descriptionIndex.size;
}
